class EvaluationItem:
    __slots__ = ("score", "cost", "label", "payload", "_insert_order")
    _global_counter: int = 0

    def __init__(self, score: float, cost: float, label: str, payload: Dict[str, Any]) -> None:
        self.score: float = score
        self.cost: float = cost
        self.label: str = label
        self.payload: Dict[str, Any] = payload
        EvaluationItem._global_counter += 1
        self._insert_order: int = EvaluationItem._global_counter

    @property
    def net_value(self) -> float:
        return self.score - self.cost

    def __lt__(self, other: "EvaluationItem") -> bool:
        if self.net_value != other.net_value:
            return self.net_value > other.net_value
        return self._insert_order < other._insert_order

    def to_dict(self) -> Dict[str, Any]:
        return {
            "label": self.label,
            "score": round(self.score, 6),
            "cost": round(self.cost, 6),
            "net_value": round(self.net_value, 6),
        }

class EvaluationPriorityQueue:
    def __init__(self, capacity: int = 1024) -> None:
        self._capacity: int = max(1, capacity)
        self._heap: List[EvaluationItem] = []
        self._total_pushed: int = 0
        self._total_evicted: int = 0

    def push(self, item: EvaluationItem) -> None:
        self._total_pushed += 1
        if len(self._heap) < self._capacity:
            heapq.heappush(self._heap, item)
        else:
            evicted = heapq.heappushpop(self._heap, item)
            if evicted is not item:
                self._total_evicted += 1

    def pop(self) -> Optional[EvaluationItem]:
        if self._heap:
            return heapq.heappop(self._heap)
        return None

    def peek(self) -> Optional[EvaluationItem]:
        if self._heap:
            return self._heap[0]
        return None

    def drain_sorted(self) -> List[EvaluationItem]:
        items = sorted(self._heap)
        self._heap = []
        return items

    @property
    def size(self) -> int:
        return len(self._heap)

    def stats(self) -> Dict[str, int]:
        return {
            "capacity": self._capacity,
            "current_size": self.size,
            "total_pushed": self._total_pushed,
            "total_evicted": self._total_evicted,
        }

class CostBenefitAnalyzer:
    def __init__(self, discount_gamma: float = 0.97, penalty: float = 0.02) -> None:
        self._gamma: float = max(0.0, min(1.5, discount_gamma))
        self._penalty: float = max(0.0, penalty)

    def discounted_score(self, raw_score: float, step: int) -> float:
        return raw_score * (self._gamma ** step)

    def penalized_cost(self, raw_cost: float, transitions: int) -> float:
        return raw_cost + self._penalty * transitions

    def net_benefit(self, raw_score: float, raw_cost: float, step: int, transitions: int) -> float:
        return self.discounted_score(raw_score, step) - self.penalized_cost(raw_cost, transitions)

    def rank_actions(self, actions: List[Dict[str, Any]], current_step: int, current_transitions: int) -> List[Dict[str, Any]]:
        ranked: List[Tuple[float, int, Dict[str, Any]]] = []
        for idx, action in enumerate(actions):
            score = float(action.get("score", 0.0))
            cost = float(action.get("cost", 0.0))
            nb = self.net_benefit(score, cost, current_step, current_transitions)
            entry = {**action, "net_benefit": round(nb, 6), "rank_order": 0}
            ranked.append((nb, idx, entry))
        ranked.sort(key=lambda t: (-t[0], t[1]))
        return [t[2] for t in ranked]

class HeuristicState:
    def __init__(self, name: str, layer: int) -> None:
        self.name: str = name
        self.layer: int = layer
        self.transitions: Dict[str, "HeuristicState"] = {}
        self.entry_count: int = 0
        self.cumulative_score: float = 0.0

    def add_transition(self, signal: str, target: "HeuristicState") -> None:
        self.transitions[signal] = target

    def enter(self, score: float) -> None:
        self.entry_count += 1
        self.cumulative_score += score

    @property
    def average_score(self) -> float:
        return self.cumulative_score / max(self.entry_count, 1)

    def to_dict(self) -> Dict[str, Any]:
        return {
            "name": self.name,
            "layer": self.layer,
            "entry_count": self.entry_count,
            "average_score": round(self.average_score, 6),
            "transitions": list(self.transitions.keys()),
        }

class HeuristicStateMachine:
    def __init__(self, layer_count: int = 5) -> None:
        self._states: Dict[str, HeuristicState] = {}
        self._current: Optional[HeuristicState] = None
        self._transition_log: List[Dict[str, Any]] = []
        self._transition_count: int = 0
        self._score_window: List[float] = []
        self._build_layers(layer_count)

    def _build_layers(self, layer_count: int) -> None:
        layer_names = ["conservative_scan", "exploratory_probe", "greedy_exploit", "balanced_adaptive", "fallback_cascade"]
        for layer_idx in range(min(layer_count, len(layer_names))):
            state = HeuristicState(name=layer_names[layer_idx], layer=layer_idx)
            self._states[state.name] = state
        state_list = list(self._states.values())
        for i, state in enumerate(state_list):
            if i + 1 < len(state_list): state.add_transition("escalate", state_list[i + 1])
            if i > 0: state.add_transition("demote", state_list[i - 1])
            state.add_transition("hold", state)
            state.add_transition("boost_mutation_sigma", state)
        if state_list: state_list[-1].add_transition("restart", state_list[0])
        self._current = state_list[0] if state_list else None

    def current_state_name(self) -> str:
        return self._current.name if self._current else "none"

    def transition(self, signal: str, score: float) -> str:
        if self._current is None: return "error_no_state"
        target = self._current.transitions.get(signal, self._current)
        previous_name = self._current.name
        self._current = target
        self._current.enter(score)
        self._transition_count += 1
        self._transition_log.append({
            "step": self._transition_count, "from": previous_name,
            "signal": signal, "to": self._current.name, "score": round(score, 6)
        })
        return self._current.name

    def decide_signal(self, score: float, exploration_epsilon: float, exploitation_bias: float, confidence_minimum: float) -> str:
        self._score_window.append(score)
        if len(self._score_window) > 15:
            self._score_window.pop(0)

        # 🚀 Compute Kinetic Velocity and Acceleration Derivatives
        if len(self._score_window) >= 3:
            velocities = [self._score_window[i] - self._score_window[i-1] for i in range(1, len(self._score_window))]
            accelerations = [velocities[i] - velocities[i-1] for i in range(1, len(velocities))]
            avg_vel = sum(velocities) / len(velocities)
            avg_acc = sum(accelerations) / len(accelerations)

            if abs(avg_vel) < 1e-5 and abs(avg_acc) < 1e-5:
                logger.info("Kinetic Stagnation Caught Preemptively. Injecting boost_mutation_sigma signal.")
                return "boost_mutation_sigma"

        if score < confidence_minimum:
            if self._current and self._current.layer >= 4: return "restart"
            return "escalate"
        normalized = score * exploitation_bias
        if normalized > (1.0 - exploration_epsilon): return "hold"
        if normalized < exploration_epsilon: return "escalate"
        if self._current and self._current.average_score > score: return "demote"
        return "hold"

    def snapshot(self) -> Dict[str, Any]:
        return {
            "current_state": self._current.to_dict() if self._current else None,
            "transition_count": self._transition_count,
            "states": {n: s.to_dict() for n, s in self._states.items()},
            "recent_transitions": self._transition_log[-10:],
        }

class FallbackRouter:
    def __init__(self, max_depth: int = 6, ttl_seconds: float = 300.0) -> None:
        self._max_depth: int = max(1, max_depth)
        self._ttl: float = ttl_seconds
        self._cache: OrderedDict[str, Tuple[Strategy, float]] = OrderedDict()
        self._cascade_order: List[Strategy] = [
            Strategy.GREEDY, Strategy.EXPLORATORY, Strategy.BALANCED,
            Strategy.CONSERVATIVE, Strategy.FALLBACK_CASCADE, Strategy.WARM_BOOTSTRAP, Strategy.RANDOM_RESTART
        ]

    def route(self, metadata: Dict[str, Any], primary_strategy: Strategy, score: float, confidence_minimum: float) -> Tuple[Strategy, int]:
        if score >= confidence_minimum: return primary_strategy, 0

        # Intercept Random Restart condition to perform an intelligent Warm Bootstrap via experience_replay
        if primary_strategy == Strategy.FALLBACK_CASCADE:
            try:
                from experience_replay import ExperienceReplayBuffer
                erb = ExperienceReplayBuffer()
                if erb.get_best_triplet():
                    return Strategy.WARM_BOOTSTRAP, self._max_depth
            except ImportError:
                pass

        return primary_strategy, 1

    def stats(self) -> Dict[str, Any]:
        return {"max_depth": self._max_depth, "cache_size": len(self._cache)}

def _generate_candidate_actions(metadata: Dict[str, Any], strategy: Strategy) -> List[Dict[str, Any]]:
    actions: List[Dict[str, Any]] = []
    base_score = float(metadata.get("current_score", 0.5))
    cycle = int(metadata.get("current_cycle", 1))

    if strategy in (Strategy.GREEDY, Strategy.EXPLORATORY, Strategy.BALANCED, Strategy.WARM_BOOTSTRAP):
        actions.append({"label": "increase_exploration_depth", "score": base_score * 1.15, "cost": 0.08 * math.log1p(cycle)})
        actions.append({"label": "tighten_convergence_tolerance", "score": base_score * 1.05, "cost": 0.05 * math.log1p(cycle)})
    if strategy in (Strategy.GREEDY, Strategy.BALANCED):
        actions.append({"label": "boost_mutation_sigma", "score": base_score * 1.20, "cost": 0.12 * math.log1p(cycle)})
    if strategy == Strategy.WARM_BOOTSTRAP:
        actions.append({"label": "apply_warm_bootstrap_vector", "score": base_score * 1.35, "cost": 0.02})
    if not actions:
        actions.append({"label": "noop_hold", "score": base_score, "cost": 0.0})
    return actions

def evaluate(metadata: Dict[str, Any], hyper_params: Dict[str, Any]) -> Dict[str, Any]:
    start_time: float = time.monotonic()
    manifest: Dict[str, Any] = _load_manifest()
    params: Dict[str, Any] = {**_get_dt_params(manifest), **hyper_params}
    thresholds: Dict[str, Any] = _get_thresholds(manifest)
    ceilings: Dict[str, Any] = _get_cost_ceilings(manifest)

    wall_limit: float = ceilings.get("decision_tree_max_wall_seconds", 15.0)
    layer_count: int = int(params.get("heuristic_layer_count", 5))
    queue_capacity: int = int(params.get("priority_queue_capacity", 1024))
    discount_gamma: float = float(params.get("cost_benefit_discount_gamma", 0.97))
    exploration_eps: float = float(params.get("exploration_epsilon", 0.15))
    exploitation_bias: float = float(params.get("exploitation_bias", 0.85))
    confidence_min: float = float(thresholds.get("decision_confidence_minimum", 0.55))

    current_score: float = float(metadata.get("current_score", 0.5))
    current_cycle: int = int(metadata.get("current_cycle", 1))

    fsm = HeuristicStateMachine(layer_count=layer_count)
    signal = fsm.decide_signal(current_score, exploration_eps, exploitation_bias, confidence_min)
    new_state = fsm.transition(signal, current_score)

    state_strategy_map = {
        "conservative_scan": Strategy.CONSERVATIVE, "exploratory_probe": Strategy.EXPLORATORY,
        "greedy_exploit": Strategy.GREEDY, "balanced_adaptive": Strategy.BALANCED, "fallback_cascade": Strategy.FALLBACK_CASCADE
    }
    primary_strategy = state_strategy_map.get(new_state, Strategy.BALANCED)

    router = FallbackRouter(max_depth=6)
    resolved_strategy, cascade_depth = router.route(metadata, primary_strategy, current_score, confidence_min)

    metadata["fsm_state"] = new_state
    metadata["fsm_signal"] = signal
    metadata["resolved_strategy"] = resolved_strategy.name

    candidates = _generate_candidate_actions(metadata, resolved_strategy)
    cba = CostBenefitAnalyzer(discount_gamma=discount_gamma)
    ranked = cba.rank_actions(candidates, current_cycle, fsm._transition_count)
    metadata["ranked_actions"] = ranked

    pq = EvaluationPriorityQueue(capacity=queue_capacity)
    for action in ranked:
        pq.push(EvaluationItem(float(action.get("score", 0.0)), float(action.get("cost", 0.0)), str(action.get("label", "unknown")), action))

    best = pq.pop()
    if best:
        metadata["selected_action"] = best.to_dict()
        metadata["selected_action_label"] = best.label
        if signal == "boost_mutation_sigma" or best.label == "boost_mutation_sigma":
            metadata["strategy_mode"] = "boost_mutation"
        else:
            metadata["strategy_mode"] = "escalate_complexity" if best.label == "increase_exploration_depth" else "hold"

    metadata["fsm_snapshot"] = fsm.snapshot()
    metadata["decision_tree_wall_seconds"] = round(time.monotonic() - start_time, 6)
    return metadata
