                    res, err = future.result()
                    results.append(res)
                    if err: aggregated_errors.append(err)
                except Exception as exc:
                    results.append({"path": future_to_path[future], "status": "failure", "error": str(exc)})

        return {
            "results": results, "errors": aggregated_errors,
            "scanned_count": sum(1 for r in results if r["status"] == "scanned"),
            "total_files": len(file_paths), "scan_duration_seconds": round(time.monotonic() - scan_start, 4)
        }

def evaluate(metadata: Dict[str, Any], hyper_params: Dict[str, Any]) -> Dict[str, Any]:
    start_time = time.monotonic()
    manifest = _load_manifest()
    params = {**_get_scanner_params(manifest), **hyper_params}

    scanner = FileScanner(worker_count=int(params.get("concurrent_worker_pool_size", 8)))
    scan_targets = metadata.get("scan_targets", [])
    if not scan_targets and metadata.get("workspace_root"):
        root = metadata["workspace_root"]
        scan_targets = [os.path.join(r, f) for r, _, files in os.walk(root) for f in files if f.endswith(".py")]

    if not scan_targets:
        metadata["scanner_status"] = "complete"
        return metadata

    scan_output = scanner.scan_files(scan_targets)
    metadata.update({
        "scan_summary": {"scanned": scan_output["scanned_count"], "total": scan_output["total_files"]},
        "scan_errors": scan_output["errors"], "scanner_wall_seconds": round(time.monotonic() - start_time, 4), "scanner_status": "complete"
    })
    return metadata
