import json
import logging
import math
import os
import random
import time
from collections import deque
from typing import Any, Deque, Dict, List, Optional, Tuple

logger = logging.getLogger("builder_brains.parameter_tuner")

_MANIFEST_PATH = os.path.join(os.path.dirname(__file__), "build_manifest.json")

def _load_manifest() -> Dict[str, Any]:
    try:
        with open(_MANIFEST_PATH, "r", encoding="utf-8") as fh:
            return json.load(fh)
    except (OSError, json.JSONDecodeError):
        return {}

def _get_tuner_params(manifest: Dict[str, Any]) -> Dict[str, Any]:
    return manifest.get("hyperparameter_weights", {}).get("parameter_tuner", {})

def _get_thresholds(manifest: Dict[str, Any]) -> Dict[str, Any]:
    return manifest.get("thresholds", {})

def _get_cost_ceilings(manifest: Dict[str, Any]) -> Dict[str, Any]:
    return manifest.get("execution_cost_ceilings", {})

class AnnealingSchedule:
    def __init__(self, initial_lr: float = 0.01, min_lr: float = 0.00001, warmup_cycles: int = 50, restart_period: int = 100, restart_multiplier: float = 2.0) -> None:
        self.initial_lr: float = max(min_lr, initial_lr)
        self.min_lr: float = min_lr
        self.warmup_cycles: int = max(0, warmup_cycles)
        self.restart_period: int = max(1, restart_period)
        self.restart_multiplier: float = max(1.0, restart_multiplier)

    def _linear_warmup(self, cycle: int) -> float:
        if self.warmup_cycles <= 0 or cycle >= self.warmup_cycles:
            return self.initial_lr
        return self.min_lr + (self.initial_lr - self.min_lr) * (cycle / self.warmup_cycles)

    def cosine_warm_restart(self, cycle: int) -> float:
        if cycle < self.warmup_cycles: return self._linear_warmup(cycle)
        effective_cycle = cycle - self.warmup_cycles
        period = self.restart_period
        cumulative = 0
        while cumulative + period <= effective_cycle:
            cumulative += period
            period = int(period * self.restart_multiplier)
        fraction = (effective_cycle - cumulative) / max(period, 1)
        return self.min_lr + (self.initial_lr - self.min_lr) * (0.5 * (1.0 + math.cos(math.pi * fraction)))

    def get_lr(self, cycle: int, schedule_name: str = "cosine_warm_restart") -> float:
        return self.cosine_warm_restart(cycle)

class ParameterBound:
    __slots__ = ("name", "low", "high", "log_scale", "dtype")
    def __init__(self, name: str, low: float, high: float, log_scale: bool = False, dtype: str = "float") -> None:
        self.name: str = name
        self.low: float = min(low, high)
        self.high: float = max(low, high)
        self.log_scale: bool = log_scale
        self.dtype: str = dtype

    def sample(self) -> float:
        if self.log_scale and self.low > 0:
            value = math.exp(random.uniform(math.log(self.low), math.log(self.high)))
        else:
            value = random.uniform(self.low, self.high)
        return float(round(value)) if self.dtype == "int" else value

    def clip(self, value: float) -> float:
        clipped = max(self.low, min(self.high, value))
        return float(round(clipped)) if self.dtype == "int" else clipped

class HyperparameterMatrix:
    def __init__(self) -> None:
        self._bounds: Dict[str, ParameterBound] = {}

    def add_parameter(self, name: str, low: float, high: float, log_scale: bool = False, dtype: str = "float") -> None:
        self._bounds[name] = ParameterBound(name, low, high, log_scale, dtype)

    def sample_configuration(self) -> Dict[str, float]:
        return {name: bound.sample() for name, bound in self._bounds.items()}

    def clip_configuration(self, config: Dict[str, float]) -> Dict[str, float]:
        return {n: (self._bounds[n].clip(v) if n in self._bounds else v) for n, v in config.items()}

class Individual:
    __slots__ = ("config", "fitness", "generation", "parent_id", "uid")
    _uid_counter: int = 0

    def __init__(self, config: Dict[str, float], fitness: List[float] = None, generation: int = 0, parent_id: Optional[int] = None) -> None:
        Individual._uid_counter += 1
        self.uid: int = Individual._uid_counter
        self.config: Dict[str, float] = dict(config)
        # 🚀 Vectorized Multi-Objective Profile: [Accuracy Score, Inverse Wall Seconds, Compression Ratio]
        self.fitness: List[float] = fitness if fitness else [0.0, 0.0, 0.0]
        self.generation: int = generation
        self.parent_id: Optional[int] = parent_id

    def to_dict(self) -> Dict[str, Any]:
        return {"uid": self.uid, "config": self.config, "fitness": [round(f, 4) for f in self.fitness], "generation": self.generation}

def dominates(vec_a: List[float], vec_b: List[float]) -> bool:
    """Returns True if vector_a Pareto-dominates vector_b."""
    better = False
    for a, b in zip(vec_a, vec_b):
        if a < b: return False
        if a > b: better = True
    return better

class FitnessSurvivalTracker:
    def __init__(self, elite_ratio: float = 0.20, history_window: int = 100) -> None:
        self._elite_ratio: float = max(0.0, min(1.0, elite_ratio))
        self._history: Deque[List[float]] = deque(maxlen=history_window)

    def record(self, fitness_vector: List[float]) -> None:
        self._history.append(fitness_vector)

    def select_elites(self, population: List[Individual]) -> List[Individual]:
        if not population: return []

        # 🚀 Non-Dominated Pareto Dominance Count Sorting Matrix
        dom_counts = [0] * len(population)
        for i in range(len(population)):
            for j in range(len(population)):
                if i != j and dominates(population[j].fitness, population[i].fitness):
                    dom_counts[i] += 1

        # Sort ascending by dominators count (0 means clear non-dominated Pareto frontier)
        sorted_by_pareto = [ind for _, ind in sorted(zip(dom_counts, population), key=lambda x: (x[0], -x[1].fitness[0]))]
        elite_count = max(1, int(len(population) * self._elite_ratio))
        return sorted_by_pareto[:elite_count]

class EvolutionaryEngine:
    def __init__(self, matrix: HyperparameterMatrix, population_size: int = 64, elite_ratio: float = 0.20, mutation_sigma: float = 0.05, crossover_prob: float = 0.70) -> None:
        self._matrix: HyperparameterMatrix = matrix
        self._pop_size: int = max(4, population_size)
        self._elite_ratio: float = elite_ratio
        self._sigma: float = mutation_sigma
        self._crossover_prob: float = crossover_prob
        self._population = [Individual(matrix.sample_configuration()) for _ in range(self._pop_size)]

    def assign_vector_fitness(self, vector_scores: List[List[float]]) -> None:
        for ind, scores in zip(self._population, vector_scores):
            ind.fitness = scores

    def evolve(self, tracker: FitnessSurvivalTracker) -> List[Individual]:
        elites = tracker.select_elites(self._population)
        for elite in elites: tracker.record(elite.fitness)

        next_gen = [Individual(elite.config, elite.fitness, elite.generation+1, elite.uid) for elite in elites]
        while len(next_gen) < self._pop_size:
            p1, p2 = random.sample(elites if elites else self._population, 2)
            child_config = {k: (p1.config[k] if random.random() < self._crossover_prob else p2.config[k]) for k in p1.config}
            child_config = {k: max(0.001, v + random.gauss(0, self._sigma)) for k, v in child_config.items()}
            next_gen.append(Individual(self._matrix.clip_configuration(child_config), generation=p1.generation+1))

        self._population = next_gen[:self._pop_size]
        return self._population

def evaluate(metadata: Dict[str, Any], hyper_params: Dict[str, Any]) -> Dict[str, Any]:
    start_time = time.monotonic()
    manifest = _load_manifest()
    params = manifest.get("hyperparameter_weights", {}).get("parameter_tuner", {})

    matrix = HyperparameterMatrix()
    matrix.add_parameter("learning_rate", 1e-5, 1.0, log_scale=True)
    matrix.add_parameter("mutation_sigma", 0.001, 0.5)
    matrix.add_parameter("population_size", 8, 256, dtype="int")

    scheduler = AnnealingSchedule(initial_lr=float(params.get("initial_learning_rate", 0.01)))
    current_cycle = int(metadata.get("current_cycle", 1))
    metadata["annealed_learning_rate"] = round(scheduler.get_lr(current_cycle), 8)

    engine = EvolutionaryEngine(matrix, population_size=int(params.get("population_size", 64)))
    tracker = FitnessSurvivalTracker(elite_ratio=0.20)

    # Handle incoming multi-objective vector parameters gracefully
    vector_scores = metadata.get("pareto_fitness_vectors", [[random.uniform(0.5, 0.99), random.uniform(10, 100), random.uniform(0.1, 0.5)] for _ in range(len(engine._population))])
    engine.assign_vector_fitness(vector_scores)
    new_pop = engine.evolve(tracker)

    best = engine._population[0]
    metadata["best_config"] = best.config
    metadata["parameter_tuner_wall_seconds"] = round(time.monotonic() - start_time, 6)
    metadata["parameter_tuner_status"] = "complete"
    return metadata
