            value = math.exp(random.uniform(math.log(self.low), math.log(self.high)))
        else:
            value = random.uniform(self.low, self.high)
        return float(round(value)) if self.dtype == "int" else value

    def clip(self, value: float) -> float:
        clipped = max(self.low, min(self.high, value))
        return float(round(clipped)) if self.dtype == "int" else clipped

